const d = $input.first().json;
const fn = d.function_name || 'unknown';
const platform = d.calendar_platform || 'none';
const crmPlatform = d.crm_platform || 'none';
const args = d.args || {};
const client = d.client || {};

let result = '';

// ── HELPER: Refresh Google OAuth token ──────────────────────
async function refreshGoogleToken(refreshToken, agentId) {
  const GOOGLE_CLIENT_ID = process.env.GOOGLE_CLIENT_ID || '';
  const GOOGLE_CLIENT_SECRET = process.env.GOOGLE_CLIENT_SECRET || '';
  if (!GOOGLE_CLIENT_ID || !refreshToken) return null;
  try {
    const tokenResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: `grant_type=refresh_token&client_id=${GOOGLE_CLIENT_ID}&client_secret=${GOOGLE_CLIENT_SECRET}&refresh_token=${refreshToken}`,
      json: true
    });
    const newToken = tokenResponse.access_token;
    if (newToken && agentId) {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: 'https://hgheyqwnrcvwtgngqdnq.supabase.co/rest/v1/hvac_premium_agent?agent_id=eq.' + agentId,
        headers: { 'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhnaGV5cXducmN2d3RnbmdxZG5xIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NDI5NTM1MiwiZXhwIjoyMDg5ODcxMzUyfQ.PENNZ2K5syVFyU3Yn6FfYZP1JEtmanlV6nTrlGaeqsg', 'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhnaGV5cXducmN2d3RnbmdxZG5xIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NDI5NTM1MiwiZXhwIjoyMDg5ODcxMzUyfQ.PENNZ2K5syVFyU3Yn6FfYZP1JEtmanlV6nTrlGaeqsg', 'Content-Type': 'application/json' },
        body: { calendar_access_token: newToken, calendar_token_expiry: new Date(Date.now() + (tokenResponse.expires_in || 3600) * 1000).toISOString() },
        json: true
      });
    }
    return newToken;
  } catch (e) { console.log('Token refresh failed:', e.message); return null; }
}

async function getGoogleToken() {
  let token = client.calendar_access_token || '';
  const refreshToken = client.calendar_refresh_token || '';
  const tokenExpiry = client.calendar_token_expiry || '';
  if (tokenExpiry) {
    const expiry = new Date(tokenExpiry).getTime();
    if (Date.now() > expiry - 300000) {
      const newToken = await refreshGoogleToken.call(this, refreshToken, d.agent_id);
      if (newToken) token = newToken;
    }
  }
  return token;
}

function getTimezoneId(tz) {
  const map = { 'Eastern Time ET': 'America/New_York', 'Central Time CT': 'America/Chicago', 'Mountain Time MT': 'America/Denver', 'Pacific Time PT': 'America/Los_Angeles', 'Alaska Time AKST': 'America/Anchorage', 'Hawaii Time HST': 'Pacific/Honolulu' };
  return map[tz] || tz || 'America/Chicago';
}

const timezone = getTimezoneId(d.timezone);
const duration = client.default_appointment_duration || 60;

// ── CHECK AVAILABILITY ──────────────────────────────────────
if (fn === 'check_availability') {
  const date = args.date || '';
  const tw = args.time_window || 'morning';
  let startHour = tw === 'morning' ? '08:00:00' : '12:00:00';
  let endHour = tw === 'morning' ? '12:00:00' : '17:00:00';

  if (platform === 'Google Calendar') {
    const token = await getGoogleToken.call(this);
    if (token) {
      try {
        const freeBusy = await this.helpers.httpRequest({
          method: 'POST', url: 'https://www.googleapis.com/calendar/v3/freeBusy',
          headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
          body: { timeMin: date + 'T' + startHour, timeMax: date + 'T' + endHour, timeZone: timezone, items: [{ id: 'primary' }] },
          json: true
        });
        const busy = freeBusy.calendars?.primary?.busy || [];
        if (busy.length === 0) {
          result = `The ${tw} slot on ${date} is available. Would you like me to book that for you?`;
        } else {
          let totalBusyMins = 0;
          for (const b of busy) { totalBusyMins += (new Date(b.end) - new Date(b.start)) / 60000; }
          const windowMins = tw === 'morning' ? 240 : 300;
          if (windowMins - totalBusyMins >= duration) {
            result = `There is still room in the ${tw} on ${date} for a ${duration}-minute appointment. Would you like me to book it?`;
          } else {
            const altTW = tw === 'morning' ? 'afternoon' : 'morning';
            result = `The ${tw} on ${date} is fully booked. Would the ${altTW} work instead?`;
          }
        }
      } catch (e) {
        console.log('Google Calendar API error:', e.message);
        result = `The ${tw} slot on ${date} is available. Would you like me to book that for you?`;
      }
    } else {
      result = `The ${tw} slot on ${date} is available. Would you like me to book that for you?`;
    }
  } else {
    result = `The ${tw} slot on ${date} is available. Would you like me to book that for you?`;
  }
}

// ── CREATE BOOKING ──────────────────────────────────────────
else if (fn === 'create_booking') {
  const name = args.caller_name || 'Customer';
  const phone = args.caller_phone || '';
  const address = args.caller_address || '';
  const date = args.date || '';
  const tw = args.time_window || 'morning';
  const jobType = args.job_type || 'Service';
  let startHour = tw === 'morning' ? '08:00:00' : '12:00:00';
  const endMs = new Date(date + 'T' + startHour).getTime() + duration * 60000;
  const endDt = new Date(endMs);
  const endHour = endDt.toISOString().split('T')[1].substring(0, 8);

  if (platform === 'Google Calendar') {
    const token = await getGoogleToken.call(this);
    if (token) {
      try {
        const event = await this.helpers.httpRequest({
          method: 'POST', url: 'https://www.googleapis.com/calendar/v3/calendars/primary/events',
          headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
          body: {
            summary: `${jobType} — ${name}`,
            description: `Service: ${jobType}\nCustomer: ${name}\nPhone: ${phone}\nAddress: ${address}\n\nBooked by Syntharra AI Receptionist`,
            location: address,
            start: { dateTime: date + 'T' + startHour, timeZone: timezone },
            end: { dateTime: date + 'T' + endHour, timeZone: timezone },
            reminders: { useDefault: false, overrides: [{ method: 'popup', minutes: 60 }, { method: 'popup', minutes: 15 }] }
          },
          json: true
        });
        console.log('[BOOKING] Google Calendar event created:', event.id);
        result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
      } catch (e) {
        console.log('Google Calendar create error:', e.message);
        result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
      }
    } else {
      result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
    }
  } else if (platform === 'Jobber Calendar' || platform === 'Jobber') {
    const token = client.calendar_access_token || client.crm_access_token || '';
    if (token) {
      try {
        // Step 1: Create client in Jobber
        const clientMutation = await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://api.getjobber.com/api/graphql',
          headers: {
            'Authorization': 'Bearer ' + token,
            'Content-Type': 'application/json',
            'X-JOBBER-GRAPHQL-VERSION': '2023-11-15'
          },
          body: {
            query: `mutation { clientCreate(input: { firstName: "${name.split(' ')[0]}", lastName: "${name.split(' ').slice(1).join(' ') || ''}", phones: [{description: MAIN, number: "${phone}", primary: true}] }) { client { id name } userErrors { message } } }`
          },
          json: true
        });
        const clientId = clientMutation?.data?.clientCreate?.client?.id || '';
        console.log('[JOBBER] Client created:', clientId);

        // Step 2: Create job
        if (clientId) {
          const jobMutation = await this.helpers.httpRequest({
            method: 'POST',
            url: 'https://api.getjobber.com/api/graphql',
            headers: {
              'Authorization': 'Bearer ' + token,
              'Content-Type': 'application/json',
              'X-JOBBER-GRAPHQL-VERSION': '2023-11-15'
            },
            body: {
              query: `mutation { jobCreate(input: { clientId: "${clientId}", title: "${jobType}", instructions: "Booked by Syntharra AI Receptionist\nService: ${jobType}\nAddress: ${address}\nPhone: ${phone}" }) { job { id jobNumber } userErrors { message } } }`
            },
            json: true
          });
          const jobId = jobMutation?.data?.jobCreate?.job?.id || '';
          console.log('[JOBBER] Job created:', jobId);
        }

        result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
      } catch (e) {
        console.log('[JOBBER] API error:', e.message);
        result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
      }
    } else {
      result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
    }
  } else {
    result = `Appointment booked for ${name} on ${date}, ${tw}, for ${jobType} at ${address}. Confirmation will be sent shortly.`;
  }
}

// ── RESCHEDULE ──────────────────────────────────────────────
else if (fn === 'reschedule_booking') {
  const newDate = args.new_date || args.date || '';
  const newTW = args.new_time_window || args.time_window || '';
  result = `Appointment rescheduled to ${newDate}${newTW ? ', ' + newTW : ''}. Updated confirmation will be sent.`;
}

// ── CANCEL ──────────────────────────────────────────────────
else if (fn === 'cancel_booking') {
  result = 'Appointment cancelled. Would you like to rebook at a different time?';
}

// ── UNKNOWN ─────────────────────────────────────────────────
else {
  result = 'I am having a little trouble with the booking system right now. Let me take your details and have someone call you back to confirm a time.';
}

return { result: result };
